import anthropic
import time

def generate_with_retry(client, prompt, max_retries=3):
    """Retry for server-side errors (5xx)."""

    for attempt in range(max_retries):
        try:
            message = client.messages.create(
                model="claude-sonnet-4-6",
                max_tokens=1024,
                messages=[{"role": "user", "content": prompt}]
            )
            return message.content[0].text

        except anthropic.InternalServerError:
            # 500 error — retry
            print("Server error, retrying...")
            time.sleep(5)

        except anthropic.APIStatusError as e:
            if e.status_code >= 500:
                # Any 5xx — retry
                print(f"Server error {e.status_code}, retrying...")
                time.sleep(5)
            else:
                # 4xx — don't retry
                print(f"Client error {e.status_code}: {e.response}")
                raise

        except Exception as e:
            print(f"Error: {e}")
            raise

    raise Exception("Max retries reached")

def get_user_friendly_message(error):
    """Return user-friendly error message."""

    if isinstance(error, anthropic.RateLimitError):
        return "We're getting a lot of requests right now. Please try again in a moment."

    elif isinstance(error, anthropic.APIConnectionError):
        return "Connection issue. Please check your internet and try again."

    elif isinstance(error, anthropic.AuthenticationError):
        return "Authentication failed. Please update your API key."

    elif isinstance(error, anthropic.PermissionDeniedError):
        return "Permission denied. We've been notified and are looking into it."

    elif isinstance(error, anthropic.InternalServerError):
        return "Server error. We've been notified and are looking into it."

    else:
        return f"An error occurred: {error}"

import Anthropic, {
