from collections import deque
import anthropic
import time

class CircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=30):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.failures = deque()
        self.last_failure_time = None
        self.is_open = False

    def record_failure(self):
        self.failures.append(time.time())
        self.last_failure_time = time.time()

        if len(self.failures) >= self.failure_threshold:
            self.is_open = True
            print("Circuit breaker opened — blocking requests")

    def record_success(self):
        if self.is_open:
            if time.time() - self.last_failure_time >= self.recovery_timeout:
                self.is_open = False
                self.failures.clear()
                print("Circuit breaker closed — resuming requests")

    def can_proceed(self):
        if not self.is_open:
            return True

        if time.time() - self.last_failure_time >= self.recovery_timeout:
            self.is_open = False
            self.failures.clear()
            return True

        return False

circuit = CircuitBreaker(failure_threshold=5, recovery_timeout=30)
client = anthropic.Anthropic()

def generate_with_circuit_breaker(prompt):
    if not circuit.can_proceed():
        raise Exception("Circuit breaker open — too many failures")

    try:
        message = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            messages=[{"role": "user", "content": prompt}]
        )
        circuit.record_success()
        return message.content[0].text

    except (anthropic.RateLimitError, anthropic.InternalServerError):
        circuit.record_failure()
        raise
